solidity_before:
// Naive — must mask and rewrite entire slot
uint256 packed = balanceSlot;
uint224 aux = value;
uint32 balance = uint32(packed);
balanceSlot = uint256(balance) | (uint256(aux) << 32);

yul_optimized:
assembly {
    let balanceSlot := keccak256(0x0c, 0x1c)
    let packed := sload(balanceSlot)
    // XOR update: only flip bits that changed
    sstore(balanceSlot, xor(packed, shl(32, xor(value, shr(32, packed)))))
}
